import sys

def sumVector(vec):
    total = 0
    for i in range(len(vec)):
        total += vec
    return total

def fibonacci(n):
    if n <= 0:
        return 0
    if n == 1:
        return 1
    return fibonacci(n - 1) + fibonacci(n - 2)

def findFirstDuplicate(arr):
    for i in range(len(arr) - 1):
        if arr == arr[i + 1]:
            return arr
    return None

def findMax(data):
    if not data:
        return None
    maxVal = data
    for val in data:
        if val > maxVal:
            maxVal = val
    return maxVal

class Record:
    def __init__(self, id, score):
        self.id = id
        self.score = score

def normalizeScores(records, maxScore):
    if maxScore == 0:
        return
    for record in records:
        record.score = (record.score / maxScore) * 100.0

def main():
    nums = [1, 2, 3, 4, 5]
    print(f"Sum: {sumVector(nums)}")

    print(f"Fib(7): {fibonacci(7)}")

    sorted_arr = [1, 2, 2, 3, 4]
    print(f"First Duplicate: {findFirstDuplicate(sorted_arr)}")

    scores = [3.5, 7.1, 2.9, 9.4, 5.0]
    print(f"Max Score: {findMax(scores)}")

    records = [Record(1, 45.0), Record(2, 90.0), Record(3, 60.0)]
    normalizeScores(records, 90.0)
    for record in records:
        print(f"ID: {record.id} | Normalized: {record.score}")

def calculate_average(numbers):
    total = 0
    for num in numbers:
        total += num
    if len(numbers) > 0:
        return total / len(numbers)
    else:
        return None


def reverse_list(lst):
    left = 0
    right = len(lst) - 1
    while left < right:
        lst, lst = lst, lst
        left += 1
        right -= 1
    return lst


def is_palindrome(s):
    s = s.lower().replace(" ", "")
    return s == s[::-1]


def factorial(n):
    if n == 0:
        return 1
    else:
        return n * factorial(n - 1)
